import{_ as a,o as r,c as d,a2 as e}from"./chunks/framework.Bkqnpl2X.js";const u=JSON.parse('{"title":"Avis 知识体系","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1780443280000}'),o={name:"about.md"};function i(s,t,h,l,n,c){return r(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="avis-知识体系" tabindex="-1">Avis 知识体系 <a class="header-anchor" href="#avis-知识体系" aria-label="Permalink to &quot;Avis 知识体系&quot;">​</a></h1><h1 id="关于-avis" tabindex="-1">关于 Avis <a class="header-anchor" href="#关于-avis" aria-label="Permalink to &quot;关于 Avis&quot;">​</a></h1><blockquote><p>全球航空航天阀门领域知识体系的活的大厦</p></blockquote><hr><h2 id="项目定位" tabindex="-1">项目定位 <a class="header-anchor" href="#项目定位" aria-label="Permalink to &quot;项目定位&quot;">​</a></h2><p><strong>Avis</strong>（Aerospace Valve Intelligence System，航空航天阀门研发智库），中文别名&quot;航空航天阀门研发设计手册&quot;，是一个开放、协同、持续演化的航空航天阀门领域知识管理平台。</p><p>Avis不是一本静态的电子书，而是一座<strong>持续生长、可交互、可协作的知识大厦</strong>。它将约60万汉字的阀门研发设计知识体系，以结构化、可搜索、可追溯的方式呈现给全球工程技术人员。</p><hr><h2 id="作者介绍" tabindex="-1">作者介绍 <a class="header-anchor" href="#作者介绍" aria-label="Permalink to &quot;作者介绍&quot;">​</a></h2><h3 id="小贤" tabindex="-1">小贤 <a class="header-anchor" href="#小贤" aria-label="Permalink to &quot;小贤&quot;">​</a></h3><ul><li><strong>航空航天阀门研发系统工程师</strong> — 长期深耕航空航天阀门领域，将系统工程方法论（INCOSE SE）系统性地应用于阀门研发全生命周期</li><li><strong>国际系统工程师 (CSEP)</strong> — 获INCOSE认证的系统工程专业人士，具备将复杂工程问题结构化、系统化解决的专业能力</li><li><strong>战略科学家</strong> — 以战略视角审视航空航天阀门技术发展脉络，构建Avis知识体系大厦</li></ul><hr><h2 id="知识体系" tabindex="-1">知识体系 <a class="header-anchor" href="#知识体系" aria-label="Permalink to &quot;知识体系&quot;">​</a></h2><p>Avis按五编结构组织内容：</p><table tabindex="0"><thead><tr><th>编次</th><th>名称</th><th>章节范围</th><th>核心主题</th></tr></thead><tbody><tr><td>第一编</td><td>绪论与基础科学</td><td>第1-5章</td><td>概论、流体力学、热力学、材料科学、选型方法论</td></tr><tr><td>第二编</td><td>设计工程</td><td>第6-26章</td><td>驱动分类、力学分析、密封设计、各类阀门设计、加工制造</td></tr><tr><td>第三编</td><td>制造工艺与试验验证</td><td>第29-36章</td><td>焊接、热处理、飞行验证、可靠性、标准体系</td></tr><tr><td>第四编</td><td>系统工程与管理</td><td>第37-52章</td><td>系统工程、项目管理、质量保证、数字孪生、故障分析</td></tr><tr><td>第五编</td><td>前沿技术与未来发展</td><td>第53-60章</td><td>智能材料、AI设计、绿色推进、成本工程</td></tr></tbody></table><hr><h2 id="技术架构" tabindex="-1">技术架构 <a class="header-anchor" href="#技术架构" aria-label="Permalink to &quot;技术架构&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>技术选型</th></tr></thead><tbody><tr><td>内容格式</td><td>Markdown</td></tr><tr><td>版本管理</td><td>Git</td></tr><tr><td>Web站点</td><td>VitePress (Vue 3)</td></tr><tr><td>托管部署</td><td>GitHub Pages</td></tr><tr><td>全文搜索</td><td>MiniSearch (内置)</td></tr><tr><td>评论系统</td><td>Giscus (GitHub Discussions)</td></tr></tbody></table><hr><h2 id="许可证" tabindex="-1">许可证 <a class="header-anchor" href="#许可证" aria-label="Permalink to &quot;许可证&quot;">​</a></h2><p>本作品采用 <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC BY-NC-SA 4.0</a> 许可协议。</p>',21)])])}const p=a(o,[["render",i]]);export{u as __pageData,p as default};
